/**
 * @summary Get files in repository
 */
export const getGetRepositoryFilesUrl = (
  id: string,
  params?: GetRepositoryFilesParams,
) => {
  const normalizedParams = new URLSearchParams();

  Object.entries(params || {}).forEach(([key, value]) => {
    if (value !== undefined) {
      normalizedParams.append(key, value === null ? "null" : value.toString());
    }
  });

  const stringifiedParams = normalizedParams.toString();

  return stringifiedParams.length > 0
    ? `/api/repositories/${id}/files?${stringifiedParams}`
    : `/api/repositories/${id}/files`;
};

export const getRepositoryFiles = async (
  id: string,
  params?: GetRepositoryFilesParams,
  options?: RequestInit,
): Promise<FileList> => {
  return customFetch<FileList>(getGetRepositoryFilesUrl(id, params), {
    ...options,
    method: "GET",
  });
};

